"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, Sparkles, Diamond, Plus, Mic, ChevronDown, Zap, SlidersHorizontal, BookOpen, Globe, X, Send, Square, LogIn, Play } from "lucide-react";
import Sidebar from "@/components/Sidebar";
import MotionMessage from "../components/MotionMessage";
import ChatInput from "../components/ChatInput";
import SourcesSidebar from "../components/SourcesSidebar";
import { useFirebaseAuth } from "../hooks/useFirebaseAuth";
import { loadChatsFromFirestore, saveChatToFirestore, deleteChatFromFirestore, deleteAllChatsFromFirestore } from "../lib/firestore";
import { YouTubeVideo, formatViewCount, formatPublishedDate } from "../lib/youtube";

interface Source {
  id: number;
  title: string;
  url: string;
  type: 'qdrant' | 'google' | 'youtube';
  snippet?: string;
}

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
  sources?: Source[];
  youtubeVideos?: YouTubeVideo[];
}

interface Chat {
  id: string;
  title: string;
  messages: Message[];
  timestamp: Date;
}

export default function GeminiChatPage() {
  const { user, isLoading: authLoading, isAuthenticated, signInWithGoogle, logout } = useFirebaseAuth();
  const [chats, setChats] = useState<Chat[]>([]);
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activeEngine, setActiveEngine] = useState<"groq" | "hf">("groq");
  const [isLoading, setIsLoading] = useState(false);
  const [inputValue, setInputValue] = useState("");
  const [selectedSpeed, setSelectedSpeed] = useState("free-slow");
  const [greeting, setGreeting] = useState("Where do you want to begin?");
  const [activeSources, setActiveSources] = useState<Source[] | null>(null);
  const [sourcesSidebarOpen, setSourcesSidebarOpen] = useState(false);
  const [highlightedSourceId, setHighlightedSourceId] = useState<number | null>(null);
  const [showLoginPrompt, setShowLoginPrompt] = useState(false);
  const abortControllerRef = useRef<AbortController | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const isNearBottomRef = useRef(true);

  const greetings = [
    "Where do you want to begin?",
    "Let's start!",
    "Ready...Lets begin",
  ];

  // Pick random greeting on mount
  useEffect(() => {
    const randomGreeting = greetings[Math.floor(Math.random() * greetings.length)];
    setGreeting(randomGreeting);
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  // Only scroll if user is near bottom (within 150px)
  const scrollToBottomIfNearBottom = () => {
    if (isNearBottomRef.current && messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  };

  // Track scroll position
  const handleScroll = () => {
    if (scrollContainerRef.current) {
      const container = scrollContainerRef.current;
      const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
      isNearBottomRef.current = distanceFromBottom < 150;
    }
  };

  const currentChat = chats.find((c) => c.id === currentChatId);

  // Track last message count to only scroll on new messages
  const lastMessageCountRef = useRef(0);

  // Load chats from Firestore when user signs in
  useEffect(() => {
    const loadChats = async () => {
      if (isAuthenticated && user) {
        console.log('Loading chats from Firestore for user:', user.id);
        const firestoreChats = await loadChatsFromFirestore(user.id);
        console.log('Loaded chats:', firestoreChats.length);
        if (firestoreChats.length > 0) {
          setChats(firestoreChats);
        }
      }
    };
    loadChats();
  }, [isAuthenticated, user?.id]);

  // Save chat to Firestore whenever it changes
  useEffect(() => {
    const saveChats = async () => {
      if (isAuthenticated && user && chats.length > 0) {
        // Save each chat that has messages
        for (const chat of chats) {
          if (chat.messages.length > 0) {
            await saveChatToFirestore(user.id, chat);
          }
        }
      }
    };
    
    // Debounce the save to avoid too many writes
    const timeout = setTimeout(saveChats, 2000);
    return () => clearTimeout(timeout);
  }, [chats, isAuthenticated, user]);

  useEffect(() => {
    // Don't auto-scroll at all during streaming to prevent glitching
    if (isLoading) return;
    
    const currentChat = chats.find((c) => c.id === currentChatId);
    const currentMessageCount = currentChat?.messages.length || 0;
    // Only scroll if a new message was added
    if (currentMessageCount > lastMessageCountRef.current) {
      scrollToBottomIfNearBottom();
    }
    lastMessageCountRef.current = currentMessageCount;
  }, [chats, currentChatId, isLoading]);

  const handleNewChat = () => {
    const newChat: Chat = {
      id: Date.now().toString(),
      title: "New conversation",
      messages: [],
      timestamp: new Date(),
    };
    setChats((prev) => [newChat, ...prev]);
    setCurrentChatId(newChat.id);
    setSidebarOpen(false);
  };

  const handleSelectChat = (id: string) => {
    setCurrentChatId(id);
    setSidebarOpen(false);
  };

  const handleDeleteChat = async (chatId: string) => {
    console.log('Deleting chat:', chatId);
    
    // Remove from local state first for immediate UI update
    setChats((prev) => prev.filter((chat) => chat.id !== chatId));
    
    // If deleting current chat, clear selection
    if (currentChatId === chatId) {
      setCurrentChatId(null);
    }
    
    // Delete from Firestore if authenticated
    if (isAuthenticated && user) {
      try {
        console.log('Deleting from Firestore for user:', user.id);
        await deleteChatFromFirestore(user.id, chatId);
        console.log('Successfully deleted from Firestore');
      } catch (error) {
        console.error('Failed to delete from Firestore:', error);
      }
    }
  };

  const handleClearAllChats = async () => {
    console.log('Clearing all chats...');
    
    // Clear local state immediately
    setChats([]);
    setCurrentChatId(null);
    
    // Delete all from Firestore if authenticated
    if (isAuthenticated && user) {
      try {
        console.log('Deleting all chats from Firestore for user:', user.id);
        await deleteAllChatsFromFirestore(user.id);
        console.log('Successfully deleted all chats from Firestore');
      } catch (error) {
        console.error('Failed to delete all chats from Firestore:', error);
      }
    }
  };

  const handleSendMessage = async (content: string, searchMode: 'standard' | 'deep-search' = 'standard', files: any[] = []) => {
    if (!content.trim()) return;

    // Check message count for unauthenticated users
    const currentChat = chats.find((c) => c.id === currentChatId);
    const messageCount = currentChat?.messages.filter(m => m.role === "user").length || 0;
    
    if (!isAuthenticated && messageCount >= 3) {
      setShowLoginPrompt(true);
      return;
    }

    let chatId = currentChatId;
    if (!chatId) {
      const newChat: Chat = {
        id: Date.now().toString(),
        title: content.slice(0, 30) + (content.length > 30 ? "..." : ""),
        messages: [],
        timestamp: new Date(),
      };
      setChats((prev) => [newChat, ...prev]);
      chatId = newChat.id;
      setCurrentChatId(chatId);
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content,
    };

    setChats((prev) =>
      prev.map((chat) =>
        chat.id === chatId
          ? { ...chat, messages: [...chat.messages, userMessage] }
          : chat
      )
    );

    setInputValue("");
    setIsLoading(true);
    
    // Create abort controller for cancellation
    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;
    
    const streamingId = `ai-streaming-${Date.now()}`;
    
    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          messages: [...(currentChat?.messages || []), userMessage].map(m => ({
            role: m.role,
            content: m.content,
          })),
          model: selectedSpeed === 'pro' ? 'groq' : 'hf',
          userId: user?.id,
          searchMode,
        }),
        signal,
      });

      if (!response.ok) throw new Error('API error');

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let currentText = "";

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          
          const chunk = decoder.decode(value, { stream: true });
          currentText += chunk;
          
          setChats((prev) =>
            prev.map((chat) =>
              chat.id === chatId
                ? {
                    ...chat,
                    messages: [
                      ...chat.messages.filter(m => m.id !== streamingId),
                      {
                        id: streamingId,
                        role: "assistant",
                        content: currentText,
                      },
                    ],
                  }
                : chat
            )
          );
        }
      }

      // Finalize message
      setChats((prev) =>
        prev.map((chat) =>
          chat.id === chatId
            ? {
                ...chat,
                messages: [
                  ...chat.messages.filter(m => m.id !== streamingId),
                  {
                    id: Date.now().toString(),
                    role: "assistant",
                    content: currentText,
                  },
                ],
              }
            : chat
        )
      );

    } catch (error) {
      if ((error as Error).name !== 'AbortError') {
        // Add error message
        setChats((prev) =>
          prev.map((chat) =>
            chat.id === chatId
              ? {
                  ...chat,
                  messages: [
                    ...chat.messages,
                    {
                      id: Date.now().toString(),
                      role: "assistant",
                      content: "Sorry, I encountered an error. Please try again.",
                    },
                  ],
                }
              : chat
          )
        );
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      
      setChats((prev) =>
        prev.map((chat) =>
          chat.id === currentChatId
            ? {
                ...chat,
                messages: [
                  ...chat.messages,
                  {
                    id: Date.now().toString(),
                    role: "assistant",
                    content: "Response was canceled",
                    isSystem: true,
                  },
                ],
              }
            : chat
        )
      );
      
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleSwitchEngine = () => {
    setActiveEngine((prev) => (prev === "groq" ? "hf" : "groq"));
  };

  const quickActions = [
    { icon: "✨", label: "Create image" },
    { icon: "🎵", label: "Create music" },
    { icon: "📝", label: "Write anything" },
    { icon: "📚", label: "Help me learn" },
    { icon: "🚀", label: "Boost my day" },
  ];

  return (
    <div className="flex h-screen bg-[#0d0d0d] text-white overflow-hidden">
      {/* Minimal Sidebar */}
      <Sidebar
        isOpen={sidebarOpen}
        setIsOpen={setSidebarOpen}
        onNewChat={handleNewChat}
        chats={chats}
        currentChatId={currentChatId}
        onSelectChat={handleSelectChat}
        onDeleteChat={handleDeleteChat}
        onClearAllChats={handleClearAllChats}
        activeEngine={activeEngine}
        onSwitchEngine={handleSwitchEngine}
        user={user}
        isAuthenticated={isAuthenticated}
        onSignIn={signInWithGoogle}
        onSignOut={logout}
      />

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Top Header */}
        <header className="flex items-center px-4 py-3 z-10">
          <button
            onClick={() => setSidebarOpen(true)}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
          >
            <Menu size={20} className="text-gray-400" />
          </button>
          
          <span className="flex-1 text-center font-medium text-gray-300 md:text-left md:flex-none md:ml-3">
            Koda-A
          </span>
        </header>

        {/* Chat Messages / Content Area */}
        <div 
          className="flex-1 overflow-y-auto px-4 relative"
          ref={scrollContainerRef}
          onScroll={handleScroll}
        >
          <div className="max-w-3xl mx-auto min-h-full flex flex-col">
            {currentChat && currentChat.messages.length > 0 ? (
              <>
                {/* Messages */}
                <div className="space-y-6 py-8 flex-1">
                  <AnimatePresence mode="popLayout">
                    {currentChat.messages.map((message) => (
                      <MotionMessage
                        key={message.id}
                        role={message.role}
                        content={message.content}
                        isSystem={(message as any).isSystem}
                      />
                    ))}
                  </AnimatePresence>
                  {isLoading && (
                    <motion.div
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="flex gap-4 py-4"
                    >
                      <div className="w-8 h-8 rounded-full bg-[#1e1e1e] flex items-center justify-center">
                        <Sparkles size={16} className="text-blue-400" />
                      </div>
                      <div className="flex-1 pt-1 space-y-2">
                        <div className="h-4 bg-gradient-to-r from-[#2a2a2a] via-[#3a3a3a] to-[#2a2a2a] rounded animate-pulse w-3/4" />
                        <div className="h-4 bg-gradient-to-r from-[#2a2a2a] via-[#3a3a3a] to-[#2a2a2a] rounded animate-pulse w-1/2" />
                      </div>
                    </motion.div>
                  )}
                  <div ref={messagesEndRef} />
                </div>

                {/* Fixed Input at bottom when messages exist */}
                <div className="sticky bottom-0 py-4 bg-[#0d0d0d]">
                  <InputPill 
                    inputValue={inputValue}
                    setInputValue={setInputValue}
                    handleSendMessage={handleSendMessage}
                    isLoading={isLoading}
                    selectedSpeed={selectedSpeed}
                    setSelectedSpeed={setSelectedSpeed}
                    onStopGeneration={handleStopGeneration}
                  />
                </div>
              </>
            ) : (
              /* Welcome Screen - with input above the fold */
              <div className="flex flex-col justify-center items-center flex-1 py-12">
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="text-center w-full"
                >
                  {/* Greeting */}
                  <div className="flex items-center justify-center mb-2">
                    <img 
                      src={selectedSpeed === "pro" ? "/logo.webp" : "/nyati.webp"} 
                      alt="" 
                      className={selectedSpeed === "pro" ? "rounded object-cover -mr-6" : "rounded object-cover mr-1"} 
                      style={{ width: selectedSpeed === "pro" ? '168px' : '112px', height: selectedSpeed === "pro" ? '168px' : '112px' }}
                    /><span className="text-xl text-gray-300">Hi</span>
                  </div>
                  
                  {/* Main question */}
                  <h1 className="text-3xl md:text-5xl font-normal text-white mb-8">
                    {greeting}
                  </h1>

                  {/* Input Pill - positioned higher on welcome screen */}
                  <div className="mb-8">
                    <InputPill 
                      inputValue={inputValue}
                      setInputValue={setInputValue}
                      handleSendMessage={handleSendMessage}
                      isLoading={isLoading}
                      selectedSpeed={selectedSpeed}
                      setSelectedSpeed={setSelectedSpeed}
                      onStopGeneration={handleStopGeneration}
                    />
                  </div>

                  {/* Quick Actions - Mobile */}
                  <div className="flex flex-col gap-3 md:hidden max-w-xs mx-auto">
                    {[
                      { icon: "✨", label: "Create image" },
                      { icon: "📝", label: "Write anything" },
                      { icon: "💡", label: "Build an idea" },
                      { icon: "🔬", label: "Deep Research" },
                    ].map((action, index) => (
                      <motion.button
                        key={index}
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: index * 0.1 }}
                        onClick={() => handleSendMessage(action.label)}
                        className="flex items-center gap-3 py-3 text-gray-300 hover:text-white transition-colors text-left"
                      >
                        <span>{action.icon}</span>
                        <span>{action.label}</span>
                      </motion.button>
                    ))}
                  </div>

                  {/* Quick Actions - Desktop */}
                  <div className="hidden md:flex items-center justify-center gap-2 flex-wrap">
                    {quickActions.map((action, index) => (
                      <motion.button
                        key={index}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.05 }}
                        onClick={() => handleSendMessage(action.label)}
                        className="flex items-center gap-2 px-4 py-2 bg-[#1e1e1e] hover:bg-[#2a2a2a] border border-[#2a2a2a] rounded-full transition-colors text-sm text-gray-300"
                      >
                        <span>{action.icon}</span>
                        <span>{action.label}</span>
                      </motion.button>
                    ))}
                  </div>
                </motion.div>
              </div>
            )}
          </div>
        </div>

        {/* Login Prompt Modal */}
        <AnimatePresence>
          {showLoginPrompt && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4"
              onClick={() => setShowLoginPrompt(false)}
            >
              <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.9, opacity: 0 }}
                className="bg-[#1e1e1e] border border-[#2a2a2a] rounded-2xl p-6 max-w-md w-full text-center"
                onClick={(e) => e.stopPropagation()}
              >
                <div className="w-12 h-12 bg-blue-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
                  <LogIn size={24} className="text-blue-400" />
                </div>
                <h3 className="text-xl font-semibold text-white mb-2">
                  Sign in to continue chatting
                </h3>
                <p className="text-gray-400 mb-6">
                  Please sign in with Google to continue chatting with Koda-AI and save your conversations.
                </p>
                <div className="flex gap-3">
                  <button
                    onClick={() => setShowLoginPrompt(false)}
                    className="flex-1 px-4 py-2 bg-[#2a2a2a] hover:bg-[#3a3a3a] rounded-xl transition-colors text-gray-300"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={() => {
                      signInWithGoogle();
                      setShowLoginPrompt(false);
                    }}
                    className="flex-1 px-4 py-2 bg-blue-500 hover:bg-blue-400 rounded-xl transition-colors text-white font-medium"
                  >
                    Sign in with Google
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </main>
    </div>
  );
}

// Input Pill Component
function InputPill({
  inputValue,
  setInputValue,
  handleSendMessage,
  isLoading,
  selectedSpeed,
  setSelectedSpeed,
  onStopGeneration,
}: {
  inputValue: string;
  setInputValue: (value: string) => void;
  handleSendMessage: (content: string) => void;
  isLoading: boolean;
  selectedSpeed: string;
  setSelectedSpeed: (value: string) => void;
  onStopGeneration?: () => void;
}) {
  const [showSpeedDropdown, setShowSpeedDropdown] = useState(false);
  const [showToolsDropdown, setShowToolsDropdown] = useState(false);
  const [showAddDropdown, setShowAddDropdown] = useState(false);
  const [selectedTool, setSelectedTool] = useState<{name: string; icon: string | React.ReactNode} | null>(null);
  const speedDropdownRef = useRef<HTMLDivElement>(null);
  const toolsDropdownRef = useRef<HTMLDivElement>(null);
  const addDropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdowns when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (speedDropdownRef.current && !speedDropdownRef.current.contains(event.target as Node)) {
        setShowSpeedDropdown(false);
      }
      if (toolsDropdownRef.current && !toolsDropdownRef.current.contains(event.target as Node)) {
        setShowToolsDropdown(false);
      }
      if (addDropdownRef.current && !addDropdownRef.current.contains(event.target as Node)) {
        setShowAddDropdown(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const speedOptions = [
    { name: "free-slow", description: "Nyati-core01", badge: null },
    { name: "pro", description: "Koda-A : fastest model available", badge: null },
  ];

  const tools = [
    { name: "Create image", icon: "grape", type: "image" },
    { name: "Deep search", icon: "globe", type: "search" },
    { name: "Guided learning", icon: "book", type: "learn" },
  ];

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-[#1e1e1e] rounded-3xl p-4 border border-[#2a2a2a] hover:border-[#3a3a3a] transition-colors relative"
    >
      <div className="flex items-center gap-3">
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") {
              handleSendMessage(inputValue);
            }
          }}
          placeholder="Ask Koda 3"
          className="flex-1 bg-transparent border-none outline-none text-white text-lg placeholder:text-gray-500"
        />
      </div>
      
      {/* Bottom row with buttons */}
      <div className="flex items-center justify-between mt-4">
        <div className="flex items-center gap-2">
          {/* Add (+) Button with Dropdown */}
          <div className="relative" ref={addDropdownRef}>
            <button 
              onClick={() => setShowAddDropdown(!showAddDropdown)}
              className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-400"
            >
              <Plus size={20} />
            </button>

            {/* Add Dropdown */}
            {showAddDropdown && (
              <div className="absolute bottom-full left-0 mb-2 w-56 bg-[#1e1e1e] border border-[#2a2a2a] rounded-2xl shadow-xl overflow-hidden z-50 p-2">
                <button 
                  disabled
                  className="flex items-center gap-3 w-full p-3 text-left opacity-50 cursor-not-allowed"
                >
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-gray-400">
                    <rect x="3" y="3" width="18" height="18" rx="2" />
                    <circle cx="8.5" cy="8.5" r="1.5" />
                    <path d="M21 15l-5-5L5 21" />
                  </svg>
                  <div>
                    <span className="text-sm text-white">Add image</span>
                    <p className="text-xs text-gray-500">Coming soon</p>
                  </div>
                </button>
              </div>
            )}
          </div>

          {/* Tools Button with Dropdown */}
          <div className="relative flex items-center gap-2" ref={toolsDropdownRef}>
            {/* Selected Tool Chip */}
            {selectedTool && (
              <div className="flex items-center gap-1 px-3 py-1.5 bg-[#2a2a2a] rounded-full text-sm text-blue-300">
                {selectedTool.icon === "grape" ? (
                  <img src="/grape.webp" alt="" className="w-4 h-4 rounded object-cover" />
                ) : selectedTool.icon === "globe" ? (
                  <Globe size={14} />
                ) : (
                  <BookOpen size={14} />
                )}
                <span>{selectedTool.name}</span>
                <button 
                  onClick={() => setSelectedTool(null)}
                  className="ml-1 p-0.5 hover:bg-white/10 rounded-full transition-colors"
                >
                  <X size={14} />
                </button>
              </div>
            )}
            
            {/* Tools Button - only show if no tool selected */}
            {!selectedTool && (
              <button 
                onClick={() => setShowToolsDropdown(!showToolsDropdown)}
                className="flex items-center gap-1 px-3 py-1.5 hover:bg-white/10 rounded-full transition-colors text-sm text-gray-400"
              >
                <SlidersHorizontal size={16} />
                <span>Tools</span>
                <ChevronDown size={14} className={`transition-transform ${showToolsDropdown ? "rotate-180" : ""}`} />
              </button>
            )}

            {/* Tools Dropdown */}
            {showToolsDropdown && (
              <div className="absolute bottom-full left-0 mb-2 w-64 bg-[#1e1e1e] border border-[#2a2a2a] rounded-2xl shadow-xl overflow-hidden z-50 p-2">
                <p className="text-sm text-white font-medium px-3 py-2">Tools</p>
                <button 
                  onClick={() => {
                    setSelectedTool({ name: "Create image", icon: "grape" });
                    setShowToolsDropdown(false);
                  }}
                  className="flex items-center gap-3 w-full p-3 hover:bg-[#2a2a2a] rounded-xl transition-colors text-left"
                >
                  <img src="/grape.webp" alt="Create" className="w-5 h-5 rounded object-cover" />
                  <span className="text-sm text-white">Create image</span>
                </button>
                <button 
                  onClick={() => {
                    setSelectedTool({ name: "Deep search", icon: "globe" });
                    setShowToolsDropdown(false);
                  }}
                  className="flex items-center gap-3 w-full p-3 hover:bg-[#2a2a2a] rounded-xl transition-colors text-left"
                >
                  <Globe size={18} className="text-gray-400" />
                  <span className="text-sm text-white">Deep search</span>
                </button>
                <button 
                  onClick={() => {
                    setSelectedTool({ name: "Guided learning", icon: "book" });
                    setShowToolsDropdown(false);
                  }}
                  className="flex items-center gap-3 w-full p-3 hover:bg-[#2a2a2a] rounded-xl transition-colors text-left"
                >
                  <BookOpen size={18} className="text-gray-400" />
                  <span className="text-sm text-white">Guided learning</span>
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Right side: Speed Selector + Send Button */}
        <div className="flex items-center gap-2">
          {/* Speed Selector with Dropdown - positioned above */}
          <div className="relative">
            <button 
              onClick={() => setShowSpeedDropdown(!showSpeedDropdown)}
              className="flex items-center gap-2 px-3 py-1.5 hover:bg-white/10 rounded-full transition-colors text-sm text-gray-400"
            >
              {selectedSpeed === "pro" ? (
                <img src="/logo.webp" alt="" className="w-4 h-4 rounded object-cover" />
              ) : (
                <img src="/nyati.webp" alt="" className="w-4 h-4 rounded object-cover" />
              )}
              <span>{selectedSpeed}</span>
              <ChevronDown size={14} className={`transition-transform ${showSpeedDropdown ? "rotate-180" : ""}`} />
            </button>

            {/* Speed Dropdown - positioned ABOVE */}
            {showSpeedDropdown && (
              <div className="absolute bottom-full right-0 mb-2 w-72 bg-[#1e1e1e] border border-[#2a2a2a] rounded-2xl shadow-xl overflow-hidden z-50">
                {speedOptions.map((option, index) => (
                  <button
                    key={index}
                    onClick={() => {
                      setSelectedSpeed(option.name);
                      setShowSpeedDropdown(false);
                    }}
                    className={`flex items-center justify-between w-full p-4 text-left hover:bg-[#2a2a2a] transition-colors ${
                      index !== speedOptions.length - 1 ? "border-b border-[#2a2a2a]" : ""
                    }`}
                  >
                    <div>
                      <p className={`text-sm font-medium ${selectedSpeed === option.name ? "text-blue-400" : "text-white"}`}>
                        {option.name}
                      </p>
                      <p className="text-xs text-gray-400 mt-0.5">{option.description}</p>
                    </div>
                    {selectedSpeed === option.name && (
                      <div className="w-5 h-5 rounded-full bg-blue-500 flex items-center justify-center">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3">
                          <polyline points="20 6 9 17 4 12" />
                        </svg>
                      </div>
                    )}
                  </button>
                ))}
              </div>
            )}
          </div>

          <button 
            onClick={() => {
              if (isLoading && onStopGeneration) {
                onStopGeneration();
              } else {
                handleSendMessage(inputValue);
              }
            }}
            disabled={!inputValue.trim() && !isLoading}
            className={`p-3 rounded-full transition-colors flex items-center justify-center ${
              inputValue.trim() || isLoading
                ? "bg-blue-500 hover:bg-blue-400 text-white" 
                : "bg-white/10 text-gray-400 cursor-not-allowed"
            }`}
          >
            {isLoading ? (
              <Square size={20} fill="currentColor" />
            ) : (
              <Send size={20} />
            )}
          </button>
        </div>
      </div>
    </motion.div>
  );
}
